<audio id="notification-ping-sound" preload="auto">
    <source src="data:audio/mp3;base64," type="audio/mpeg">
</audio>

<script>
    window.playNotificationSound = function() {
        const audio = document.getElementById('notification-ping-sound');
        if (audio) {
            audio.currentTime = 0;
            audio.play().catch(e => console.log("L'audio n'a pas pu être lu automatiquement (politique du navigateur/interaction requise)."));
        }
    };
</script>
